private async handleStateTransition(_req: http.IncomingMessage, res: http.ServerResponse, body: string): Promise<void> {
    if (!this.stateManager) {
        this.sendJsonResponse(res, 503, this.errorBody('SERVICE_UNAVAILABLE', 'StateManager not initialized'));
        return;
    }
    try {
        const reqBody = JSON.parse(body) as StateTransitionRequest;
        if (!reqBody.workItemId || reqBody.fromState === undefined || !reqBody.toState) {
            this.sendJsonResponse(res, 400, this.errorBody('INVALID_REQUEST', 'workItemId, fromState, and toState are required'));
            return;
        }
        await this.stateManager.transition(
            reqBody.workItemId,
            reqBody.fromState,
            reqBody.toState,
            reqBody.actor,
            reqBody.workflowType,
            reqBody.extraPayload,
        );
        const newState = this.stateManager.getState(reqBody.workItemId);
        this.sendJsonResponse(res, 200, this.successBody(newState));
    } catch (err) {
        this.handleHandlerError(res, err);
    }
}
