private async handleEventLog(_req: http.IncomingMessage, res: http.ServerResponse, body: string): Promise<void> {
    if (!this.wal) {
        this.sendJsonResponse(res, 503, this.errorBody('SERVICE_UNAVAILABLE', 'WAL not initialized'));
        return;
    }
    try {
        const reqBody = JSON.parse(body) as EventLogRequest;
        if (!reqBody.projectId || !reqBody.category || !reqBody.action || !reqBody.payload) {
            this.sendJsonResponse(res, 400, this.errorBody('INVALID_REQUEST', 'projectId, category, action, and payload are required'));
            return;
        }
        const event = this.wal.createEvent(
            reqBody.projectId,
            reqBody.category,
            reqBody.action,
            reqBody.payload,
            reqBody.actor,
            reqBody.source,
        );
        await this.wal.appendEvent(event);
        this.sendJsonResponse(res, 200, this.successBody({ eventId: event.eventId }));
    } catch (err) {
        this.handleHandlerError(res, err);
    }
}
