### handleEventQuery
```typescript
private async handleEventQuery(_req: http.IncomingMessage, res: http.ServerResponse, body: string): Promise<void> {
    if (!this.wal) {
        this.sendJsonResponse(res, 503, this.errorBody('SERVICE_UNAVAILABLE', 'WAL not initialized'));
        return;
    }
    try {
        const filters: EventQueryRequest = body.trim() ? JSON.parse(body) : {};
        const allEvents = await this.wal.readAllEvents();

        let results = allEvents;

        if (filters.projectId) {
            results = results.filter(e => e.projectId === filters.projectId);
        }
        if (filters.category) {
            results = results.filter(e => e.category === filters.category);
        }
        if (filters.action) {
            results = results.filter(e => e.action === filters.action);
        }
        if (filters.actor) {
            results = results.filter(e => e.actor === filters.actor);
        }
        if (filters.fromTs !== undefined) {
            results = results.filter(e => e.ts >= filters.fromTs!);
        }
        if (filters.toTs !== undefined) {
            results = results.filter(e => e.ts <= filters.toTs!);
        }

        const offset = filters.offset ?? 0;
        if (filters.limit !== undefined) {
            results = results.slice(offset, offset + filters.limit);
        } else if (offset > 0) {
            results = results.slice(offset);
        }

        this.sendJsonResponse(res, 200, this.successBody(results));
    } catch (err) {
        this.handleHandlerError(res, err);
    }
}
```

