private async handleCasRetrieve(req: http.IncomingMessage, res: http.ServerResponse, _body: string, match: RouteMatch): Promise<void> {
    try {
        const url = new URL(req.url ?? '/', `http://localhost:${this.port ?? 0}`);
        const reference = url.searchParams.get('reference');
        if (!reference) {
            this.sendJsonResponse(res, 400, this.errorBody('INVALID_REQUEST', 'reference query parameter is required'));
            return;
        }
        const data = await this.cas.retrieve(reference);
        if (data === null) {
            this.sendJsonResponse(res, 404, this.errorBody('NOT_FOUND', `Blob not found: ${reference}`));
            return;
        }
        this.sendJsonResponse(res, 200, this.successBody({ content: data.toString('utf-8') }));
    } catch (err) {
        this.handleHandlerError(res, err);
    }
}
```

